"(function() {
  try {
    if (!window.addedRequestInterceptor) {
      window.broadcastRequest = function(request) {
        if (!request || !request.url) return;
         if (window.MuppetPage && typeof window.MuppetPage.dispatch === 'function') {
          try {
            // Mirror TS: dispatch object; bridge serializes to JSON for native
            window.MuppetPage.dispatch({
              type: 'xhr',
              request: request
            });
          } catch (e) {}
        }
      };

      window.getLowerCasedHeaders = function(headers) {
        headers = headers || {};
        var lowerCasedHeaders = {};
        for (var key in headers) {
          if (Object.prototype.hasOwnProperty.call(headers, key)) {
            lowerCasedHeaders[String(key).toLowerCase()] = headers[key];
          }
        }
        return lowerCasedHeaders;
      };

      window.originalFetch = window.fetch;

      window.fetch = async function() {
        var startTime = new Date();
        var args = Array.prototype.slice.call(arguments);
        var request = {
          type: 'fetch',
          url: '',
          method: '',
          headers: {},
          data: {}
        };

        var stringify = function(value) { return (value == null) ? '' : String(value); };

        var fetchRequest = (args[0] instanceof Request) ? args[0] : new Request(args[0], args[1]);

        var requestBody;
        var requestHeaders = {};

        try {
          fetchRequest.headers.forEach(function(value, key) {
            requestHeaders[key] = value;
          });

          requestHeaders = window.getLowerCasedHeaders(requestHeaders);

          requestBody = requestHeaders['content-type'] && requestHeaders['content-type'].includes('application/json')
            ? await fetchRequest.clone().json()
            : await fetchRequest.clone().text();
        } catch (error) {
          console.error('Error parsing fetch request', error);
        }

        try {
          request.url = stringify(fetchRequest.url);
          request.method = stringify(fetchRequest.method).toLowerCase();
          request.headers = requestHeaders;
          request.data = requestBody;
        } catch (error) {
          console.error('Error running request interceptor', error);
        }

        var response = await window.originalFetch(fetchRequest);
        var endTime = new Date();
        request.startTime = startTime.toISOString();
        request.endTime = endTime.toISOString();
        request.duration = endTime - startTime;

        var tmpHeaders = {};
        try {
          response.headers.forEach(function(value, key) {
            tmpHeaders[key] = value;
          });
        } catch (e) {
          // ignore header iteration errors
        }
        var responseHeaders = window.getLowerCasedHeaders(tmpHeaders);

        try {
          var responseCopy = response.clone();
          var responseBody = (responseHeaders['content-type'] && responseHeaders['content-type'].includes('application/json'))
            ? await responseCopy.json()
            : await responseCopy.text();

          request.response = {
            status: response.status,
            headers: responseHeaders,
            data: responseBody
          };
        } catch (error) {
          console.error('Error running response interceptor', error);
        }

        window.broadcastRequest(request);

        return response;
      };

      var openCopy = XMLHttpRequest.prototype.open;
      var sendCopy = XMLHttpRequest.prototype.send;

      XMLHttpRequest.prototype.open = function(method, url) {
        this.url = url;
        this.method = (method || '').toLowerCase();

        this.addEventListener('load', function() {
          var endTime = new Date();
          var responseHeaders = {};
          var raw = this.getAllResponseHeaders();
          if (raw) {
            raw.trim().split(/[\r\n]+/).forEach(function(line) {
              var parts = line.split(': ');
              var header = parts.shift();
              if (header) responseHeaders[header] = parts.join(': ');
            });
          }

          responseHeaders = window.getLowerCasedHeaders(responseHeaders);

          try {
            var responseBody = (responseHeaders['content-type'] && responseHeaders['content-type'].includes('application/json') && typeof this.response === 'string')
              ? JSON.parse(this.response)
              : this.response;

            if (this.request) {
              this.request.startTime = this.requestStartTime.toISOString();
              this.request.endTime = endTime.toISOString();
              this.request.duration = endTime - this.requestStartTime;
              this.request.response = {
                status: this.status,
                headers: responseHeaders,
                data: responseBody
              };
            }
          } catch (error) {
            console.error('Error running response interceptor', error);
          }

          if (this.request) window.broadcastRequest(this.request);
        });

        return openCopy.apply(this, arguments);
      };

      XMLHttpRequest.prototype.wrappedSetRequestHeader = XMLHttpRequest.prototype.setRequestHeader;

      XMLHttpRequest.prototype.setRequestHeader = function(header, value) {
        this.wrappedSetRequestHeader(header, value);
        this.requestHeaders = this.requestHeaders || {};
        this.requestHeaders[String(header).toLowerCase()] = value;
      };

      XMLHttpRequest.prototype.send = function(body) {
        var startTime = new Date();
        this.requestStartTime = startTime;
        var request = {
          type: 'xhr',
          url: '',
          method: '',
          headers: {},
          data: {}
        };

        try {
          var requestHeaders = window.getLowerCasedHeaders(this.requestHeaders);
          var requestBody = (requestHeaders['content-type'] && requestHeaders['content-type'].includes('application/json') && typeof body === 'string')
            ? JSON.parse(body)
            : body;

          request.url = this.url;
          request.method = this.method;
          request.headers = requestHeaders;
          request.data = requestBody;
          this.request = request;
        } catch (error) {
          console.error('Error running request interceptor', error);
        }

        return sendCopy.apply(this, arguments);
      };

      window.addedRequestInterceptor = true;
    }
  } catch (e) {
    console.error('request interception script error', e);
  }
})()"

"(function() {
  if (!document.querySelector('[autocomplete="one-time-code"]')) {
    window.uplinkPasswordManager = document.querySelector(
      '#uplink-password-manager'
    )

    if (!window.uplinkPasswordManager) {
      window.uplinkPasswordManager = document.createElement('input')
      window.uplinkPasswordManager.id = 'uplink-password-manager'
      window.uplinkPasswordManager.type = 'password'
      window.uplinkPasswordManager.style.opacity = '0'
      window.uplinkPasswordManager.style.height = '0'
      window.uplinkPasswordManager.style.width = '0'
      document.body?.appendChild(window.uplinkPasswordManager)
    }
  }
})()"
